package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.io.StringWriter;

class JsonWriterTest {

  private JsonWriter jsonWriter;

  @BeforeEach
  void setUp() {
    jsonWriter = new JsonWriter(new StringWriter());
  }

  @Test
  void testIsLenient_DefaultIsFalse() {
    // By default, lenient should be false
    assertFalse(jsonWriter.isLenient());
  }

  @Test
  void testIsLenient_AfterSetLenientTrue() {
    jsonWriter.setLenient(true);
    assertTrue(jsonWriter.isLenient());
  }

  @Test
  void testIsLenient_AfterSetLenientFalse() {
    jsonWriter.setLenient(true);
    jsonWriter.setLenient(false);
    assertFalse(jsonWriter.isLenient());
  }
}
